const incoming = $input.item.json;
const chatId = incoming?.message?.chat?.id || incoming?.callback_query?.message?.chat?.id || null;
if (!chatId) return { authorized: false, chat_id: null };
return { chat_id: chatId };

const members = $input.item.json;
const chatId = $('Estrai Chat ID').item.json.chat_id;
if (!Array.isArray(members) || members.length === 0) {
  return { authorized: false, chat_id: chatId, role: null, member_id: null, member_name: null };
}
const m = members[0];
return { authorized: true, chat_id: chatId, role: m.role, member_id: m.id, member_name: m.name };

// ================================================================
// CALLBACK HANDLER v4
// Gestisce: APPROVE, DISCARD, REGEN, CHARACTER_SELECT
// ================================================================
const callback = $('Telegram Trigger').item.json.callback_query;
const data = callback.data;
const chatId = callback.message.chat.id;
const messageId = callback.message.message_id;
const member = $('Valida Membro').item.json;

let action = 'unknown';
let shortId = '';
let characterId = '';

if (data === 'DISCARD') {
  action = 'discard';
} else if (data.startsWith('APPROVE::')) {
  action = 'approve';
  shortId = data.replace('APPROVE::', '');
  if (!['admin', 'approver'].includes(member.role)) action = 'unauthorized_action';
} else if (data.startsWith('REGEN::')) {
  action = 'regen';
  shortId = data.replace('REGEN::', '');
} else if (data.startsWith('CHAR::')) {
  // NEW: selezione personaggio via inline keyboard
  action = 'character_select';
  characterId = data.replace('CHAR::', '');
}

return { action, short_id: shortId, character_id: characterId, chat_id: chatId, message_id: messageId, member_id: member.member_id, member_name: member.member_name, role: member.role };

const records = $input.item.json;
const cb = $('Elabora Callback').item.json;
if (!Array.isArray(records) || records.length === 0) return { ...cb, image_record: null, error: 'Record non trovato' };
const rec = records[0];
return { ...cb, image_id: rec.id, image_url: rec.image_url, user_request: rec.user_request, character_id: rec.character_id, prompt: rec.prompt, lora_scale: rec.lora_scale };

// ================================================================
// CHARACTER SELECTOR v4
// Se c'è UN solo personaggio → va diretto alla generazione.
// Se ce ne sono PIÙ di uno → mostra inline keyboard con la scelta.
// Se arriva da CHAR:: callback → usa il personaggio selezionato.
// Se arriva da REGEN → usa character_id del record originale.
// ================================================================
const characters = $input.item.json;
const member = $('Valida Membro').item.json;
const trigger = $('Telegram Trigger').item.json;

if (!Array.isArray(characters) || characters.length === 0) {
  throw new Error('Nessun personaggio attivo nel database.');
}

let userRequest = '';
let chatId = member.chat_id;
let selectedCharId = null;

// Caso 1: callback CHAR:: (utente ha appena scelto il personaggio)
if (trigger.callback_query && $('Elabora Callback').item.json.action === 'character_select') {
  selectedCharId = $('Elabora Callback').item.json.character_id;
  // La user_request è stata salvata come caption del messaggio precedente
  // la recuperiamo dal testo del messaggio originale nel callback
  userRequest = trigger.callback_query.message.caption || trigger.callback_query.message.text || '';
  // Pulizia: rimuovi la riga "Scegli il personaggio:" se presente
  userRequest = userRequest.replace(/^🎭.*\n\n?/m, '').trim();
}
// Caso 2: REGEN (usa il personaggio dell'immagine originale)
else if (trigger.callback_query && $('Elabora Callback').item.json.action === 'regen') {
  selectedCharId = $('Unisci Dati Callback').item.json.character_id;
  userRequest = $('Unisci Dati Callback').item.json.user_request;
}
// Caso 3: messaggio di testo normale
else {
  userRequest = trigger.message.text || '';
}

// Se un solo personaggio attivo → scegli automaticamente
if (characters.length === 1) {
  selectedCharId = characters[0].id;
}

// Se non è ancora stato selezionato → segnala per mostrare keyboard
if (!selectedCharId) {
  return {
    show_character_selector: true,
    characters: characters.map(c => ({ id: c.id, name: c.name })),
    user_request: userRequest,
    chat_id: chatId,
    member_id: member.member_id,
    member_name: member.member_name
  };
}

// Trova il personaggio selezionato
const char = characters.find(c => c.id === selectedCharId) || characters[0];

const characterSheet = [
  `${char.trigger_word} woman`,
  char.age,
  char.ethnicity,
  char.hair,
  char.eyes,
  char.body,
  char.style,
  char.distinctive,
  'consistent appearance',
  'same person'
].filter(Boolean).join(', ');

return {
  show_character_selector: false,
  character_id: char.id,
  character_sheet: characterSheet,
  character_name: char.name,
  trigger_word: char.trigger_word,
  lora_model: char.lora_model,
  lora_version: char.lora_version,
  lora_scale: char.lora_scale,
  content_pillars: char.content_pillars || [],
  user_request: userRequest,
  chat_id: chatId,
  member_id: member.member_id,
  member_name: member.member_name
};

// Costruisce dinamicamente l'inline keyboard con i personaggi disponibili
const data = $input.item.json;
const chars = data.characters;

// Crea i bottoni (max 2 per riga per leggibilità)
const rows = [];
for (let i = 0; i < chars.length; i += 2) {
  const buttons = [{ text: `🎭 ${chars[i].name}`, callback_data: `CHAR::${chars[i].id}` }];
  if (chars[i + 1]) buttons.push({ text: `🎭 ${chars[i + 1].name}`, callback_data: `CHAR::${chars[i + 1].id}` });
  rows.push({ inline_keyboard: [buttons] });
}

return {
  chat_id: data.chat_id,
  user_request: data.user_request,
  keyboard_json: JSON.stringify({ inline_keyboard: rows.flatMap(r => r.inline_keyboard) })
};

