const response = $input.item.json;
const sheet = $('Estrai ID Record').item.json;
if (!response.choices?.[0]) throw new Error('Risposta Claude non valida');
const raw = response.choices[0].message.content;
const cleaned = raw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
const match = cleaned.match(/\{[\s\S]*\}/);
const DEFAULT_NEG = 'different person, inconsistent face, bad anatomy, bad hands, text, watermark, blurry, deformed, ugly, mutation, extra limbs, low quality';
let parsed;
try { parsed = JSON.parse(match ? match[0] : cleaned); } catch(e) { parsed = { prompt: cleaned, negative_prompt: DEFAULT_NEG, pillar: 'lifestyle' }; }
let prompt = (parsed.prompt || '').trim();
if (!prompt.toLowerCase().includes(sheet.trigger_word.toLowerCase())) prompt = `${sheet.trigger_word} woman, ${prompt}`;
return { ...sheet, prompt, negative_prompt: (parsed.negative_prompt || DEFAULT_NEG).trim(), content_pillar: parsed.pillar || 'lifestyle' };

const rep = $input.item.json;
const prev = $('Elabora Prompt').item.json;
let imageUrl = rep.output ? (Array.isArray(rep.output) ? rep.output[0] : rep.output) : null;
if (!imageUrl) throw new Error('Nessuna immagine. Status: ' + (rep.status||'?') + ' Error: ' + (rep.error||'?'));
return { ...prev, image_url: imageUrl, generation_time_ms: Date.now() - (prev.generation_start || Date.now()) };

