// ================================================================
// QUALITY CHECK PARSER
// Legge la risposta di Claude Vision e decide se passare o rigenerare
// ================================================================
const visionResponse = $input.item.json;
const prev = $('Estrai URL Immagine').item.json;

if (!visionResponse.choices?.[0]) {
  // Se Claude Vision fallisce, lascia passare (meglio preview che blocco)
  return { ...prev, quality_pass: true, quality_score: null, quality_issues: [], quality_verdict: 'Validazione non disponibile' };
}

const raw = visionResponse.choices[0].message.content;
const cleaned = raw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
const match = cleaned.match(/\{[\s\S]*\}/);

let qc;
try {
  qc = JSON.parse(match ? match[0] : cleaned);
} catch(e) {
  return { ...prev, quality_pass: true, quality_score: null, quality_issues: [], quality_verdict: 'Parse error — lasciata passare' };
}

const pass = qc.pass === true && (qc.score || 0) >= 70;

return {
  ...prev,
  quality_pass: pass,
  quality_score: qc.score || 0,
  quality_issues: qc.issues || [],
  quality_verdict: qc.verdict || ''
};

// Prepara il secondo tentativo incrementando il contatore
const prev = $input.item.json;
return {
  ...prev,
  attempt: (prev.attempt || 1) + 1,
  generation_start: Date.now()
};

